  ('optometrist-moex-02279', 'optometrist', 'optometrist-moex-108-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '將馬竇氏鏡（Maddox rod）置於患者的右眼前，並使馬竇氏鏡的條狀鏡片成水平，所見紅色光條在光點的 右邊時，則患者眼位為下列何者？', '["內斜", "外斜", "上斜", "下斜"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:52+00:00", "source_pdf_sha1": "29132c54255c", "answer_pdf_sha1": "4ae5d106f009", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "112", "s": "1103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
